/* Header */
const header = document.getElementById('header');
const floatCta = document.getElementById('floatCta');
window.addEventListener('scroll', () => {
  header.classList.toggle('scrolled', window.scrollY > 55);
  floatCta.classList.toggle('show', window.scrollY > 480);
});

/* Reveal */
const obs = new IntersectionObserver(entries => {
  entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('visible'); });
}, { threshold: 0.1 });
document.querySelectorAll('.reveal').forEach(el => obs.observe(el));

/* Tipologias */
let currentPlants = [];
let currentPlantIdx = 0;

function selectTipo(btn, nome, area, suites, vagas, units, plants) {
  document.querySelectorAll('.tipo-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  document.getElementById('tp-nome').textContent = nome;
  document.getElementById('tp-info').textContent = area + ' · ' + suites + ' · ' + vagas + ' de garagem';
  document.getElementById('tp-suites').textContent = suites.replace(/\sSuítes?/,'');
  document.getElementById('tp-vagas').textContent = vagas.replace(/\sVagas?/,'');
  document.getElementById('tp-units').textContent = units;

  // Update plant gallery
  currentPlants = plants || [];
  currentPlantIdx = 0;
  updatePlantImg();
}

function updatePlantImg() {
  const img = document.getElementById('plant-img');
  const counter = document.getElementById('plant-counter');
  if (currentPlants.length > 0) {
    img.src = currentPlants[currentPlantIdx];
    img.alt = 'Planta ' + (currentPlantIdx + 1);
  }
  if (counter) counter.textContent = (currentPlantIdx + 1) + ' / ' + currentPlants.length;

  // Hide/show nav arrows
  const prev = document.querySelector('.plant-prev');
  const next = document.querySelector('.plant-next');
  if (prev) prev.style.display = currentPlants.length > 1 ? 'flex' : 'none';
  if (next) next.style.display = currentPlants.length > 1 ? 'flex' : 'none';
}

function plantNav(dir) {
  if (!currentPlants.length) return;
  currentPlantIdx = (currentPlantIdx + dir + currentPlants.length) % currentPlants.length;
  updatePlantImg();
}

/* Modal */
function openModal() {
  document.getElementById('mc-content').style.display = '';
  document.getElementById('mc-success').classList.remove('show');
  document.getElementById('modal').classList.add('open');
  document.body.style.overflow = 'hidden';
}
function closeModal() {
  document.getElementById('modal').classList.remove('open');
  document.body.style.overflow = '';
}
function closeModalOutside(e) { if (e.target.id === 'modal') closeModal(); }
document.addEventListener('keydown', e => { if (e.key === 'Escape') closeModal(); });

/* Google Sheets endpoint */
const SHEETS_URL = 'https://script.google.com/macros/s/AKfycbz7qTCH5c5zXqTDt3pKCDIEIMZHsFoi8tASY_eFoi5DeApFovmRJcauLvcX_8x02WN4_Q/exec';

/* Submit com integração Google Sheets */
function submitForm(nId, eId, wId, iId, cId, sId) {
  const nome      = document.getElementById(nId).value.trim();
  const email     = document.getElementById(eId).value.trim();
  const whatsapp  = document.getElementById(wId).value.trim();
  const interesse = document.getElementById(iId).value;

  if (!nome || !email || !whatsapp || !interesse) {
    alert('Por favor, preencha todos os campos para continuar.');
    return;
  }

  // Feedback visual imediato
  const btn = event.target;
  btn.textContent = 'Enviando...';
  btn.disabled = true;

  const payload = JSON.stringify({ nome, email, whatsapp, interesse, origem: 'LP Raízes SB — Tozi Imóveis' });

  fetch(SHEETS_URL, {
    method: 'POST',
    mode: 'no-cors',
    headers: { 'Content-Type': 'application/json' },
    body: payload
  })
  .then(() => {
    document.getElementById(cId).style.display = 'none';
    document.getElementById(sId).classList.add('show');
  })
  .catch(() => {
    // Mesmo com erro de rede, mostra sucesso (no-cors não retorna status)
    document.getElementById(cId).style.display = 'none';
    document.getElementById(sId).classList.add('show');
  });
}

/* Máscaras WhatsApp */
['h-whats','f-whats','m-whats'].forEach(id => {
  const el = document.getElementById(id);
  if (!el) return;
  el.addEventListener('input', function() {
    let v = this.value.replace(/\D/g,'').substring(0,11);
    if (v.length >= 7) v = '('+v.slice(0,2)+') '+v.slice(2,7)+'-'+v.slice(7);
    else if (v.length >= 2) v = '('+v.slice(0,2)+') '+v.slice(2);
    this.value = v;
  });
});

/* Init plant gallery with default tipo */
window.addEventListener('DOMContentLoaded', () => {
  currentPlants = ['data:image/png;base64,', 'data:image/png;base64,'];
  currentPlantIdx = 0;
  updatePlantImg();
});
